299	function getSpecData(slug: string): Record<string, any> {
300	  const dir = path.join(SPECS_DIR, slug);
301	  const data: Record<string, any> = { slug, status: deriveStatus(slug) };
302	
303	  const briefPath = path.join(dir, 'brief.md');
304	  if (fs.existsSync(briefPath)) data.brief = fs.readFileSync(briefPath, 'utf-8').trim();
305	
306	  const scopePath = path.join(dir, 'scope.yaml');
307	  if (fs.existsSync(scopePath)) data.scope = parse(fs.readFileSync(scopePath, 'utf-8'));
308	
309	  const decisionsPath = path.join(dir, 'decisions.yaml');
310	  if (fs.existsSync(decisionsPath)) data.decisions = parse(fs.readFileSync(decisionsPath, 'utf-8'));
311	
312	  const specPath = path.join(dir, 'spec.md');
313	  if (fs.existsSync(specPath)) data.spec = fs.readFileSync(specPath, 'utf-8');
314	
315	  const inventoryPath = path.join(dir, 'inventory.md');
316	  if (fs.existsSync(inventoryPath)) data.inventory = fs.readFileSync(inventoryPath, 'utf-8');
317	
318	  const observationsPath = path.join(dir, 'observations.md');
319	  if (fs.existsSync(observationsPath)) data.observations = fs.readFileSync(observationsPath, 'utf-8');
320	
321	  const gapsPath = path.join(dir, 'gaps.yaml');
322	  if (fs.existsSync(gapsPath)) data.gaps = fs.readFileSync(gapsPath, 'utf-8');
323	
324	  // Read meta
325	  const meta = readMeta(slug);
326	  if (meta.codex) data.codex = meta.codex;
327	  if (meta.sessionId) data.readerSessionId = meta.sessionId;
328	  if (meta.writId) {
329	    data.writId = meta.writId;
330	    const writ = getWritSync(meta.writId);
331	    if (writ) data.writStatus = writ.status;
332	  }
333	
334	  // Include running process info
335	  const r = running.get(slug);
336	  if (r) {
337	    data.runningStep = r.step;
338	    data.runningLog = r.log.join('\n');
339	    data.runningElapsed = Math.floor((Date.now() - r.startTime) / 1000);
340	    data.runningTokens = r.tokenCount;
341	  }
342	
343	  return data;
344	}
345	
346	function slugify(text: string): string {
347	  return text
348	    .toLowerCase()
349	    .replace(/[^a-z0-9\s-]/g, '')
350	    .replace(/\s+/g, '-')
351	    .replace(/-+/g, '-')
352	    .replace(/^-|-$/g, '')
353	    .slice(0, 60);
354	}
355	
356	// ── SSE ───────────────────────────────────────────────────────────────
357	
358	function sendSSE(slug: string, event: string, data: any): void {
359	  const payload = 'event: ' + event + '\ndata: ' + JSON.stringify(data) + '\n\n';
360	  for (let i = sseClients.length - 1; i >= 0; i--) {
361	    const client = sseClients[i];
362	    if (client.slug === slug) {
363	      try {
364	        client.res.write(payload);
365	      } catch {
366	        sseClients.splice(i, 1);
367	      }
368	    }

