// ── Pipeline Cost Tracking ───────────────────────────────────────────

// Anthropic pricing per million tokens
const MODEL_PRICING: Record<string, { input: number; output: number; cacheWrite: number; cacheRead: number }> = {
  'claude-opus-4-6':         { input: 15,  output: 75,  cacheWrite: 18.75, cacheRead: 1.875 },
  'claude-sonnet-4-20250514': { input: 3,   output: 15,  cacheWrite: 3.75,  cacheRead: 0.30 },
};
const DEFAULT_PRICING = MODEL_PRICING['claude-opus-4-6'];

interface StepCost {
  step: string;
  inputTokens: number;
  outputTokens: number;
  cacheWriteTokens: number;
  cacheReadTokens: number;
  costUsd: number;
  model: string | null;
}

interface PipelineCosts {
  steps: StepCost[];
  totalCostUsd: number;
  totalInputTokens: number;
  totalOutputTokens: number;
}

function computePipelineCosts(slug: string): PipelineCosts | null {
  const transcriptDir = path.join(SPECS_DIR, slug, 'planner-transcripts');
  if (!fs.existsSync(transcriptDir)) return null;

  const files = fs.readdirSync(transcriptDir).filter(f => f.endsWith('.jsonl')).sort();
  if (files.length === 0) return null;

  // Group by session ID — resumed sessions share transcripts, so we need to deduplicate.
  // For each session, collect which steps used it (from filename prefix).
  // The latest step's transcript is the cumulative one — use it for that session's total,
  // then delta to get per-step costs.
  const sessionSteps = new Map<string, string[]>(); // sessionId → [step names in pipeline order]
  const sessionFiles = new Map<string, string>();    // sessionId → latest filename

  const stepOrder = ['reader', 'analyst', 'writer'];

  for (const f of files) {
    const match = f.match(/^(reader|analyst|writer)-(.+)\.jsonl$/);
    if (!match) continue;
    const [, step, sessionId] = match;
    if (!sessionSteps.has(sessionId)) sessionSteps.set(sessionId, []);
    sessionSteps.get(sessionId)!.push(step);
    // Keep the latest (highest step order) file for this session
    const existing = sessionFiles.get(sessionId);
    if (!existing || stepOrder.indexOf(step) > stepOrder.indexOf(existing.split('-')[0])) {
      sessionFiles.set(sessionId, f);
    }
  }

  // For each session, parse the cumulative transcript and compute usage per step boundary.
  // Since resumed sessions accumulate, we parse message-by-message and attribute to steps
  // based on the system prompt changes (or just sum everything per session and attribute
  // to the latest step for simplicity).
  //
  // Simpler approach: for each step, find the transcript file with the MOST messages for
  // that step. Parse all assistant messages and sum usage. For non-resumed sessions this
  // is exact. For resumed sessions, we take the delta.

  const stepTotals = new Map<string, StepCost>();

  // Process each session group
  for (const [sessionId, steps] of sessionSteps) {
    steps.sort((a, b) => stepOrder.indexOf(a) - stepOrder.indexOf(b));

    // Parse ALL assistant messages from the cumulative transcript
    const cumulativeFile = sessionFiles.get(sessionId)!;
    const allMessages = parseTranscriptUsage(path.join(transcriptDir, cumulativeFile));

    // For single-step sessions, all messages belong to that step
    if (steps.length === 1) {
      const step = steps[0];
      const existing = stepTotals.get(step);
      const cost = sumUsage(allMessages);
      if (existing) {
        mergeStepCost(existing, cost);
      } else {
        stepTotals.set(step, { step, ...cost });
      }
    } else {
      // Multi-step (resumed) session — parse each step's transcript and delta
      let prevTotal = { inputTokens: 0, outputTokens: 0, cacheWriteTokens: 0, cacheReadTokens: 0, costUsd: 0, model: null as string | null };

      for (const step of steps) {
        const stepFile = `${step}-${sessionId}.jsonl`;
        const stepPath = path.join(transcriptDir, stepFile);
        if (!fs.existsSync(stepPath)) continue;

        const stepMessages = parseTranscriptUsage(stepPath);
        const stepTotal = sumUsage(stepMessages);

        // Delta from previous step's cumulative total
        const delta = {
          inputTokens: stepTotal.inputTokens - prevTotal.inputTokens,
          outputTokens: stepTotal.outputTokens - prevTotal.outputTokens,
          cacheWriteTokens: stepTotal.cacheWriteTokens - prevTotal.cacheWriteTokens,
          cacheReadTokens: stepTotal.cacheReadTokens - prevTotal.cacheReadTokens,
          costUsd: stepTotal.costUsd - prevTotal.costUsd,
          model: stepTotal.model,
        };

        const existing = stepTotals.get(step);
        if (existing) {
          mergeStepCost(existing, delta);
        } else {
          stepTotals.set(step, { step, ...delta });
        }

        prevTotal = stepTotal;
      }
    }
  }

  const stepsResult: StepCost[] = [];
  for (const step of stepOrder) {
    const s = stepTotals.get(step);
    if (s) stepsResult.push(s);
  }

  if (stepsResult.length === 0) return null;

  return {
    steps: stepsResult,
    totalCostUsd: stepsResult.reduce((sum, s) => sum + s.costUsd, 0),
    totalInputTokens: stepsResult.reduce((sum, s) => sum + s.inputTokens, 0),
    totalOutputTokens: stepsResult.reduce((sum, s) => sum + s.outputTokens, 0),
  };
}

interface UsageSummary {
  inputTokens: number;
  outputTokens: number;
  cacheWriteTokens: number;
  cacheReadTokens: number;
  costUsd: number;
  model: string | null;
}

function parseTranscriptUsage(filePath: string): Array<{ model: string; input: number; output: number; cacheWrite: number; cacheRead: number }> {
  const messages: Array<{ model: string; input: number; output: number; cacheWrite: number; cacheRead: number }> = [];
  try {
    const content = fs.readFileSync(filePath, 'utf-8');
    for (const line of content.split('\n')) {
      if (!line.trim()) continue;
      const obj = JSON.parse(line);
      if (obj.type === 'assistant' && obj.message?.usage) {
        const usage = obj.message.usage;
        messages.push({
          model: obj.message.model || 'unknown',
          input: usage.input_tokens || 0,
          output: usage.output_tokens || 0,
          cacheWrite: usage.cache_creation_input_tokens || 0,
          cacheRead: usage.cache_read_input_tokens || 0,
        });
      }
    }
  } catch { /* ignore parse errors */ }
  return messages;
}

function sumUsage(messages: Array<{ model: string; input: number; output: number; cacheWrite: number; cacheRead: number }>): UsageSummary {
  let inputTokens = 0, outputTokens = 0, cacheWriteTokens = 0, cacheReadTokens = 0;
  let model: string | null = null;
  for (const m of messages) {
    inputTokens += m.input;
    outputTokens += m.output;
    cacheWriteTokens += m.cacheWrite;
    cacheReadTokens += m.cacheRead;
    if (m.model !== 'unknown') model = m.model;
  }
  const pricing = (model && MODEL_PRICING[model]) || DEFAULT_PRICING;
  const costUsd = (inputTokens * pricing.input + outputTokens * pricing.output +
    cacheWriteTokens * pricing.cacheWrite + cacheReadTokens * pricing.cacheRead) / 1_000_000;
  return { inputTokens, outputTokens, cacheWriteTokens, cacheReadTokens, costUsd, model };
}

function mergeStepCost(target: StepCost, source: UsageSummary): void {
  target.inputTokens += source.inputTokens;
  target.outputTokens += source.outputTokens;
  target.cacheWriteTokens += source.cacheWriteTokens;
  target.cacheReadTokens += source.cacheReadTokens;
  target.costUsd += source.costUsd;
  if (source.model) target.model = source.model;
}

