npx tsx -e "
import fs from 'fs';
import path from 'path';

const MODEL_PRICING = {
  'claude-opus-4-6': { input: 15, output: 75, cacheWrite: 18.75, cacheRead: 1.875 },
};

function parseAndSum(filePath) {
  let i = 0, o = 0, cw = 0, cr = 0;
  for (const line of fs.readFileSync(filePath, 'utf-8').split('\n')) {
    if (!line.trim()) continue;
    const obj = JSON.parse(line);
    if (obj.type === 'assistant' && obj.message?.usage) {
      const u = obj.message.usage;
      i += u.input_tokens || 0;
      o += u.output_tokens || 0;
      cw += u.cache_creation_input_tokens || 0;
      cr += u.cache_read_input_tokens || 0;
    }
  }
  const p = MODEL_PRICING['claude-opus-4-6'];
  return { i, o, cw, cr, cost: (i * p.input + o * p.output + cw * p.cacheWrite + cr * p.cacheRead) / 1e6 };
}

const base = 'specs/scriptorium-doc-has-multiple-stale/planner-transcripts';
const sid1 = '54e1c1e7-d1fd-4171-b081-3aba67e9c2f6';

const reader = parseAndSum(path.join(base, 'reader-' + sid1 + '.jsonl'));
const analyst = parseAndSum(path.join(base, 'analyst-' + sid1 + '.jsonl'));
const writer = parseAndSum(path.join(base, 'writer-' + sid1 + '.jsonl'));

console.log('Session', sid1);
console.log('reader  lines:', fs.readFileSync(path.join(base, 'reader-' + sid1 + '.jsonl'), 'utf-8').split('\n').length, ' cost:', reader.cost.toFixed(2));
console.log('analyst lines:', fs.readFileSync(path.join(base, 'analyst-' + sid1 + '.jsonl'), 'utf-8').split('\n').length, ' cost:', analyst.cost.toFixed(2));
console.log('writer  lines:', fs.readFileSync(path.join(base, 'writer-' + sid1 + '.jsonl'), 'utf-8').split('\n').length, ' cost:', writer.cost.toFixed(2));
console.log();
console.log('reader delta: \$' + reader.cost.toFixed(2));
console.log('analyst delta: \$' + (analyst.cost - reader.cost).toFixed(2));
console.log('writer delta: \$' + (writer.cost - analyst.cost).toFixed(2));
console.log('total: \$' + writer.cost.toFixed(2));
