'\n' +
'/* ── Decisions tab ── */\n' +
'.filters { display: flex; gap: 10px; margin-bottom: 16px; align-items: center; }\n' +
'.filters span { color: var(--text-dim); font-size: 12px; }\n' +
'.filter-chip { padding: 4px 12px; border-radius: 12px; border: 1px solid var(--border);\n' +
