'}\n' +
'\n' +
'function renderDecisions() {\n' +
'  if (!specData.decisions) return \'<div class="empty">No decisions.yaml yet. Run the analyst first.</div>\';\n' +
'\n' +
'  var html = \'<div class="filters">\';\n' +
