'  }\n' +
'  html += \'</div>\';\n' +
'\n' +
'  var excluded = {};\n' +
'  if (specData.scope) {\n' +
'    specData.scope.scope.forEach(function(s) { if (!s.included) excluded[s.id] = true; });\n' +
'  }\n' +
'\n' +
'  var decisions = specData.decisions.decisions.filter(function(d) {\n' +
