664	function startReader(slug: string, brief: string): void {
665	  // Pre-create session ID for forking
666	  const sessionId = crypto.randomUUID();
667	  const meta = readMeta(slug);
668	  meta.sessionId = sessionId;
669	  writeMeta(slug, meta);
670	
