'});\n' +
'\n' +
'document.addEventListener("keydown", function(e) {\n' +
'  if (e.key !== "Enter") return;\n' +
'  var target = e.target;\n' +
'  if (target.dataset && target.dataset.action === "custom-input") {\n' +
'    var value = target.value.trim();\n' +
