'        renderDetail();\n' +
'      });\n' +
'    }\n' +
'  }\n' +
'});\n' +
'\n' +
'function esc(s) {\n' +
'  if (!s) return "";\n' +
'  return String(s).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");\n' +
'}\n' +
'function escAttr(s) {\n' +
'  if (!s) return "";\n' +
'  return String(s).replace(/&/g, "&amp;").replace(/"/g, "&quot;").replace(/</g, "&lt;").replace(/>/g, "&gt;");\n' +
'}\n' +
'\n' +
'route();\n' +
