'    showDetail(currentSlug);\n' +
'  }\n' +
'}\n' +
'window.addEventListener("hashchange", route);\n' +
'\n' +
'// ── API helpers ──\n' +
'function api(method, path, body) {\n' +
'  var opts = { method: method, headers: { "Content-Type": "application/json" } };\n' +
