'}\n' +
'\n' +
'function renderDetail() {\n' +
'  var d = specData;\n' +
'  var el = document.getElementById("app");\n' +
'  var html = "";\n' +
'\n' +
'  html += \'<a class="back" href="#/">&larr; all specs</a>\';\n' +
