'    }\n' +
'  });\n' +
'}\n' +
'\n' +
'// ── Detail view ──\n' +
'function showDetail(slug) {\n' +
'  cleanup();\n' +
'  api("GET", "/specs/" + slug).then(function(data) {\n' +
