    try {
      const platform = process.platform;
      if (platform === 'darwin') execSync('open ' + url);
      else if (platform === 'linux') execSync('xdg-open ' + url + ' 2>/dev/null || true');
    } catch { /* silent */ }
  });
}).catch((err) => {
  console.error('[workshop] Failed to boot guild:', err.message);
  process.exit(1);
});

