import fs from 'fs';
import path from 'path';

const MODEL_PRICING: Record<string, any> = {
  'claude-opus-4-6': { input: 15, output: 75, cacheWrite: 18.75, cacheRead: 1.875 },
};
const DEFAULT_PRICING = MODEL_PRICING['claude-opus-4-6'];

interface TMsg { uuid: string|null; model: string; input: number; output: number; cacheWrite: number; cacheRead: number; }

function parseTranscriptUsage(filePath: string): TMsg[] {
  const messages: TMsg[] = [];
  try {
    const content = fs.readFileSync(filePath, 'utf-8');
    for (const line of content.split('\n')) {
      if (!line.trim()) continue;
      const obj = JSON.parse(line);
      if (obj.type === 'assistant' && obj.message?.usage) {
        const u = obj.message.usage;
        messages.push({
          uuid: obj.uuid || null,
          model: obj.message.model || 'unknown',
          input: u.input_tokens || 0,
          output: u.output_tokens || 0,
          cacheWrite: u.cache_creation_input_tokens || 0,
          cacheRead: u.cache_read_input_tokens || 0,
        });
      }
    }
  } catch {}
  return messages;
}

function sumUsage(messages: TMsg[]) {
  let inputTokens = 0, outputTokens = 0, cacheWriteTokens = 0, cacheReadTokens = 0;
  let model: string | null = null;
  for (const m of messages) {
    inputTokens += m.input; outputTokens += m.output;
    cacheWriteTokens += m.cacheWrite; cacheReadTokens += m.cacheRead;
    if (m.model !== 'unknown') model = m.model;
  }
  const pricing = (model && MODEL_PRICING[model]) || DEFAULT_PRICING;
  const costUsd = (inputTokens * pricing.input + outputTokens * pricing.output +
    cacheWriteTokens * pricing.cacheWrite + cacheReadTokens * pricing.cacheRead) / 1_000_000;
  return { inputTokens, outputTokens, cacheWriteTokens, cacheReadTokens, costUsd, model };
}

const SPECS_DIR = 'specs';
const stepOrder = ['reader', 'analyst', 'writer'];

for (const slug of ['implement-ability-to-pause-rigs', 'doc-update-pass', 'more-doc-updates', 'scriptorium-doc-has-multiple-stale']) {
  const tdir = path.join(SPECS_DIR, slug, 'planner-transcripts');
  if (!fs.existsSync(tdir)) continue;

  const files = fs.readdirSync(tdir).filter(f => f.endsWith('.jsonl')).sort();
  const stepFiles = new Map<string, string[]>();
  for (const f of files) {
    const match = f.match(/^(reader|analyst|writer)-(.+)\\.jsonl\$/);
    if (!match) continue;
    if (!stepFiles.has(match[1])) stepFiles.set(match[1], []);
    stepFiles.get(match[1])!.push(f);
  }

  const seenUuids = new Set<string>();
  console.log('=== ' + slug + ' ===');
  let total = 0;
  for (const step of stepOrder) {
    const transcripts = stepFiles.get(step);
    if (!transcripts) continue;
    let stepCost = 0;
    for (const f of transcripts) {
      const msgs = parseTranscriptUsage(path.join(tdir, f));
      const newMsgs = msgs.filter(m => {
        if (m.uuid && seenUuids.has(m.uuid)) return false;
        if (m.uuid) seenUuids.add(m.uuid);
        return true;
      });
      const usage = sumUsage(newMsgs);
      stepCost += usage.costUsd;
    }
    total += stepCost;
    console.log('  ' + step + ': \$' + stepCost.toFixed(2));
  }
  console.log('  TOTAL: \$' + total.toFixed(2));
  console.log();
}
"

