'    html += \'</div>\';\n' +
'\n' +
'    if (specs.length === 0) {\n' +
'      html += \'<div class="empty">No specs yet. Write a brief above to get started.</div>\';\n' +
'    } else {\n' +
'      for (var i = 0; i < specs.length; i++) {\n' +
